j:jelly.g:evaluate:

var api = new MttrDashboardAPI();
var r = api.getHistoricalQueriesByTeam();
r ? JSON.stringify(r) : '';

j:jelly.script:
google.charts.load('current', { packages: ['corechart'] });
google.charts.setOnLoadCallback(function() { setTimeout(drawHistQryTeam, 100); });

var _rtHQT = null;
function _scheduleRedrawHQT() {
    if (_rtHQT) clearTimeout(_rtHQT);
    _rtHQT = setTimeout(drawHistQryTeam, 150);
}
// Idempotent listener setup — see mttr_widget_hist_inc_priority.xml
// for the rationale (SN re-renders re-run this script; naive
// addEventListener leaks a handler on every mount).
if (window.__mttrHistQryTeamState) {
    window.removeEventListener('resize', window.__mttrHistQryTeamState.resizeHandler);
    if (window.__mttrHistQryTeamState.observer) {
        window.__mttrHistQryTeamState.observer.disconnect();
    }
}
window.addEventListener('resize', _scheduleRedrawHQT);
var _obsHQT = null;
if (typeof ResizeObserver !== 'undefined') {
    _obsHQT = new ResizeObserver(_scheduleRedrawHQT);
    _obsHQT.observe(document.getElementById('chart_hist_qry_team'));
}
window.__mttrHistQryTeamState = { resizeHandler: _scheduleRedrawHQT, observer: _obsHQT };

var TEAM_COLORS_HQT = ['#4dc9f6','#f67019','#f53794','#00a950',
                        '#8549ba','#ff6384','#36a2eb','#cddc39'];

function drawHistQryTeam() {
    try {
        var _el = document.getElementById('chart_hist_qry_team');
        var _w = _el.offsetWidth;
        if (_w > 0) {
            _el.style.height = Math.max(300, Math.round(_w * 0.5)) + 'px';
        }
        var raw = document.getElementById('mttr_data_hist_qry_team').value;
        if (!raw || raw === 'null') { noDataHQT(); return; }
        var resp = JSON.parse(raw);
        if (!resp || !resp.periods || resp.periods.length === 0) {
            noDataHQT(); return;
        }

        var periods = resp.periods;
        var series = resp.series;
        var teamNames = Object.keys(series).sort();

        var header = ['Period'];
        for (var t = 0; teamNames.length > t; t++) {
            header.push(teamNames[t]);
        }

        var rows = [header];
        for (var p = 0; periods.length > p; p++) {
            var row = [periods[p]];
            for (var ti = 0; teamNames.length > ti; ti++) {
                var entry = series[teamNames[ti]][periods[p]];
                var hrs = entry ? entry.mttr_hours : 0;
                row.push(Math.round((hrs / 24) * 10) / 10);
            }
            rows.push(row);
        }

        var data = google.visualization.arrayToDataTable(rows);

        // Set formatted tooltips
        for (var fp = 0; periods.length > fp; fp++) {
            for (var ft = 0; teamNames.length > ft; ft++) {
                var e = series[teamNames[ft]][periods[fp]];
                if (e) {
                    var h = e.mttr_hours || 0;
                    var dm = Math.round(h * 60);
                    var dd = Math.floor(dm / (60 * 24));
                    var dh = Math.floor((dm % (60 * 24)) / 60);
                    var dmin = dm % 60;
                    data.setFormattedValue(fp, ft + 1,
                        dd + 'd ' + dh + 'h ' + dmin + 'm (' + e.total_cases + ' cases)');
                }
            }
        }

        var chart = new google.visualization.LineChart(
            document.getElementById('chart_hist_qry_team'));
        chart.draw(data, {
            chartArea: { width: '80%', height: '65%' },
            legend: { position: 'bottom', textStyle: { fontSize: 10 } },
            colors: TEAM_COLORS_HQT,
            backgroundColor: 'transparent',
            vAxis: {
                title: 'MTTR (Days)',
                format: '#.#',
                textStyle: { fontSize: 10 },
                viewWindow: { min: 0 }
            },
            hAxis: { textStyle: { fontSize: 11 }, slantedText: false },
            pointSize: 5,
            lineWidth: 2,
            curveType: 'function',
            tooltip: { textStyle: { fontSize: 11 } }
        });
    } catch (e) {
        console.error('mttr_widget_hist_qry_team error:', e);
        noDataHQT();
    }
}

function noDataHQT() {
    // DOM-API placeholder — see mttr_widget_team_trend.xml for
    // the full rationale (escaped-entity innerHTML rendered as
    // literal text; createElement produces a real p node).
    var container = document.getElementById('chart_hist_qry_team');
    container.innerHTML = '';
    var p = document.createElement('p');
    p.style.color = '#999';
    p.style.textAlign = 'center';
    p.style.padding = '40px';
    p.textContent = 'No historical data available';
    container.appendChild(p);
}
